@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_element">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int TimeoutSeconds { get; set; } = 300;
    [Parameter] public EventCallback OnIdle { get; set; }
    [Parameter] public EventCallback OnActive { get; set; }

    private ElementReference _element;
    private IJSObjectReference? _jsModule;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;
    private System.Timers.Timer? _timer;
    private bool _isIdle;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        _dotNetRef = DotNetObjectReference.Create(this);
        _jsModule = await JS.InvokeAsync<IJSObjectReference>(
            "import", "./_content/sv-0047e50435804900af354fee3ed27c20/Components/UserActivityTracker.razor.js");

        await _jsModule.InvokeVoidAsync("initialize", _element, _dotNetRef);

        _timer = new System.Timers.Timer(TimeoutSeconds * 1000);
        _timer.AutoReset = false;
        _timer.Elapsed += OnTimerElapsed;
        _timer.Start();
    }

    [JSInvokable]
    public void OnUserActivity()
    {
        if (_timer is null) return;

        _timer.Stop();
        _timer.Start();

        if (_isIdle)
        {
            _isIdle = false;
            InvokeAsync(OnActive.InvokeAsync);
        }
    }

    private void OnTimerElapsed(object? sender, System.Timers.ElapsedEventArgs e)
    {
        if (_isIdle) return;
        _isIdle = true;
        InvokeAsync(OnIdle.InvokeAsync);
    }

    public async ValueTask DisposeAsync()
    {
        if (_timer is not null)
        {
            _timer.Elapsed -= OnTimerElapsed;
            _timer.Stop();
            _timer.Dispose();
            _timer = null;
        }

        if (_jsModule is not null)
        {
            try
            {
                await _jsModule.InvokeVoidAsync("dispose");
                await _jsModule.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }

        _dotNetRef?.Dispose();
    }
}

let element = null;
let dotNetRef = null;

const events = ["mousemove", "keydown", "click", "scroll"];

function handleActivity() {
    dotNetRef?.invokeMethodAsync("OnUserActivity");
}

export function initialize(el, ref) {
    element = el;
    dotNetRef = ref;
    for (const event of events) {
        element.addEventListener(event, handleActivity, { passive: true });
    }
}

export function dispose() {
    if (element) {
        for (const event of events) {
            element.removeEventListener(event, handleActivity);
        }
    }
    element = null;
    dotNetRef = null;
}

